using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpHttpServer.Tools;

[McpServerToolType]
public static class WeatherTools
{
    [McpServerTool, Description("Gets the current weather for a given city.")]
    public static string GetWeather(string city)
    {
        // Simulated weather data
        return $"The weather in {city} is 72°F and sunny.";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpHttpServer.Resources;

[McpServerResourceType]
public static class ConfigResources
{
    /// <summary>
    /// A fixed resource that returns the application's configuration data.
    /// Clients can read this via the "config://app" URI.
    /// </summary>
    [McpServerResource(UriTemplate = "config://app", Name = "app-config",
        MimeType = "application/json"),
     Description("Returns the application configuration.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = "Production",
            Features = new { Logging = true, Caching = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    /// <summary>
    /// A resource template that returns configuration for a named section.
    /// Clients can read this via URIs like "config://database" or "config://auth".
    /// </summary>
    [McpServerResource(UriTemplate = "config://{section}", Name = "section-config",
        MimeType = "application/json"),
     Description("Returns configuration for a specific section.")]
    public static string GetSectionConfig(string section)
    {
        var data = section.ToLowerInvariant() switch
        {
            "database" => new { Host = "localhost", Port = 5432, Name = "appdb" } as object,
            "auth"     => new { Provider = "OAuth2", TokenLifetimeMins = 60 },
            _          => new { Error = $"Unknown section: {section}" }
        };

        return JsonSerializer.Serialize(data, new JsonSerializerOptions { WriteIndented = true });
    }
}

